class Solution:
    def minimumFinishTime(self, tires, changeTime, numLaps):
        INF = float('inf')
        max_k = min(numLaps, 20)
        best = [INF] * (max_k + 1)
        max_f = max(f for f, r in tires)
        cap = (max_f + changeTime) * numLaps + 1
        for f, r in tires:
            total = 0
            term = f
            j = 1
            while j <= max_k:
                total += term
                if total < best[j]:
                    best[j] = total
                if term > cap:
                    break
                term *= r
                j += 1
        dp = [INF] * (numLaps + 1)
        dp[0] = 0
        for i in range(1, numLaps + 1):
            for j in range(1, min(i, max_k) + 1):
                prev = dp[i - j]
                if prev == INF:
                    continue
                extra = changeTime if i - j > 0 else 0
                cand = prev + extra + best[j]
                if cand < dp[i]:
                    dp[i] = cand
        return dp[numLaps]

