var minimumFinishTime = function(tires, changeTime, numLaps) {
    const maxK = Math.min(numLaps, 20);
    const best = new Array(maxK + 1).fill(Infinity);
    let maxF = 0;
    for (const t of tires) if (t[0] > maxF) maxF = t[0];
    const cap = (maxF + changeTime) * numLaps + 1;
    for (const [f, r] of tires) {
        let total = 0;
        let term = f;
        let j = 1;
        while (j <= maxK) {
            total += term;
            if (total < best[j]) best[j] = total;
            if (term > cap) break;
            term *= r;
            j++;
        }
    }
    const dp = new Array(numLaps + 1).fill(Infinity);
    dp[0] = 0;
    for (let i = 1; i <= numLaps; i++) {
        for (let j = 1; j <= Math.min(i, maxK); j++) {
            const prev = dp[i - j];
            if (prev === Infinity) continue;
            const extra = (i - j > 0) ? changeTime : 0;
            const cand = prev + extra + best[j];
            if (cand < dp[i]) dp[i] = cand;
        }
    }
    return dp[numLaps];
};
